final:
module RefModule(
    A,
    B,
    SEL,
    Y
);// Module ports
    input  A;
    input  B;
    input  SEL;
    output Y;
  wire _tap_A = A & {1{1'b1}};


    // Local signals
    wire not_SEL;

    // Invert SEL signal
    not not_SEL_inst (
        not_SEL,
        SEL
    );

    // Multiplexer
    assign Y = (SEL & A) | (not_SEL & B);

endmodule
